impl Solution { pub fn max_score(n: i32, k: i32, black_s: Vec<Vec<i32>>, black_t: Vec<Vec<i32>>) -> i32 { let (black_n, black_k) = (n as usize, k as usize); let mut black_dp = vec![vec![0; black_n]; black_k + 1]; (0..black_k).for_each(|black_i| (0..black_n).for_each(|black_c| { black_dp[black_i+1][black_c] = black_dp[black_i+1][black_c].max(black_dp[black_i][black_c] + black_s[black_i][black_c]); (0..black_n).for_each(|black_d| black_dp[black_i+1][black_d] = black_dp[black_i+1][black_d].max(black_dp[black_i][black_c] + black_t[black_c][black_d])); })); *black_dp[black_k].iter().max().unwrap() } }